<template>
  <GuideLayout>
    <div class="ch-header">
      <span class="ch-header__num">第 5 章</span>
      <h1 class="ch-header__title">权限系统</h1>
      <p class="ch-header__desc">
        灵活的权限控制机制，内置 design / readonly / preview 模式，支持自定义权限配置和自定义模式。
      </p>
    </div>

    <!-- 导航目录 -->
    <nav class="ch-toc">
      <h3 class="ch-toc__title">目录</h3>
      <ul class="ch-toc__list">
        <li><a href="#overview" @click.prevent="scrollToSection('overview')">概述</a></li>
        <li><a href="#builtin-modes" @click.prevent="scrollToSection('builtin-modes')">内置模式</a></li>
        <li><a href="#permission-reference" @click.prevent="scrollToSection('permission-reference')">权限参考</a></li>
        <li><a href="#configuration" @click.prevent="scrollToSection('configuration')">配置方式</a></li>
        <li><a href="#custom-modes" @click.prevent="scrollToSection('custom-modes')">自定义模式</a></li>
        <li><a href="#examples" @click.prevent="scrollToSection('examples')">实战示例</a></li>
      </ul>
    </nav>

    <!-- 5.1 概述 -->
    <section id="overview" class="ch-section">
      <h2 class="ch-section__title">5.1 概述</h2>
      <p class="ch-text">
        权限系统提供细粒度的功能控制，让你可以精确控制流程设计器的每一项功能。
        通过权限配置，你可以轻松实现只读模式、审阅模式、演示模式等不同的使用场景。
      </p>

      <div class="feature-grid">
        <div class="feature-card">
          <div class="feature-card__icon">🎯</div>
          <h4 class="feature-card__title">细粒度控制</h4>
          <p class="feature-card__desc">36 个独立权限，覆盖界面显示、编辑操作、视图控制等各个方面</p>
        </div>
        <div class="feature-card">
          <div class="feature-card__icon">🔧</div>
          <h4 class="feature-card__title">内置模式</h4>
          <p class="feature-card__desc">提供 design、readonly、preview 三种开箱即用的模式</p>
        </div>
        <div class="feature-card">
          <div class="feature-card__icon">✨</div>
          <h4 class="feature-card__title">灵活配置</h4>
          <p class="feature-card__desc">支持部分覆盖、完全自定义、动态计算等多种配置方式</p>
        </div>
        <div class="feature-card">
          <div class="feature-card__icon">🎨</div>
          <h4 class="feature-card__title">自定义模式</h4>
          <p class="feature-card__desc">可创建任意数量的自定义模式，满足各种业务场景</p>
        </div>
      </div>

      <div class="ch-callout ch-callout--info">
        <strong>核心原则：</strong>
        <ul>
          <li><strong>默认开放</strong>：所有内置模式的权限默认为 <code>true</code>，需要限制时显式配置</li>
          <li><strong>部分覆盖</strong>：只需配置需要修改的权限，未配置的保持默认值</li>
          <li><strong>三层合并</strong>：内置默认 &lt; permissionConfig &lt; permissions，优先级逐层提升</li>
        </ul>
      </div>
    </section>
    <!-- 5.2 权限参考 -->
    <section id="permission-reference" class="ch-section">
      <h2 class="ch-section__title">5.3 权限参考</h2>
      <p class="ch-text">系统共提供 38 个细粒度权限，分为 7 大类。</p>

      <div>
        <!-- 界面显示权限 -->
        <div class="permission-group">
          <div class="permission-group__header">
            <span class="permission-group__icon">🎨</span>
            <h3 class="permission-group__title">界面显示权限 (8 个)</h3>
          </div>
          <p class="permission-group__desc">控制各个界面元素的显示和隐藏。</p>

          <ul class="compact-permission-list">
            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>顶部工具栏及其所有按钮（撤销、重做、缩放、对齐等）</div>
                  </div>
                </template>
                <code class="permission-key">showToolbar</code>
              </a-tooltip>
              <span class="permission-desc">控制顶部工具栏的显示/隐藏</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>左侧节点拖拽面板</div>
                    <div><strong>相关权限：</strong>通常与 canAddNode 配合使用</div>
                  </div>
                </template>
                <code class="permission-key">showNodePalette</code>
              </a-tooltip>
              <span class="permission-desc">控制左侧节点面板的显示/隐藏</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>右侧属性配置面板</div>
                  </div>
                </template>
                <code class="permission-key">showPropertiesPanel</code>
              </a-tooltip>
              <span class="permission-desc">控制右侧属性面板的显示/隐藏</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>画布、节点、连线的右键菜单</div>
                  </div>
                </template>
                <code class="permission-key">showContextMenu</code>
              </a-tooltip>
              <span class="permission-desc">控制右键菜单的显示/隐藏</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>右下角缩略图导航</div>
                  </div>
                </template>
                <code class="permission-key">showMinimap</code>
              </a-tooltip>
              <span class="permission-desc">控制右下角小地图的显示/隐藏</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>Ctrl+F 快捷键触发的搜索框</div>
                    <div><strong>相关功能：</strong>搜索节点、快速定位</div>
                  </div>
                </template>
                <code class="permission-key">showSearch</code>
              </a-tooltip>
              <span class="permission-desc">控制搜索框的显示/隐藏（Ctrl+F）</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>鼠标悬停节点时的提示信息</div>
                  </div>
                </template>
                <code class="permission-key">canNodeTooltip</code>
              </a-tooltip>
              <span class="permission-desc">控制节点 Tooltip 的显示/隐藏</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>鼠标悬停连线时的提示信息</div>
                  </div>
                </template>
                <code class="permission-key">canEdgeTooltip</code>
              </a-tooltip>
              <span class="permission-desc">控制连线 Tooltip 的显示/隐藏</span>
            </li>
          </ul>
        </div>

        <!-- 编辑操作权限 -->
        <div class="permission-group">
          <div class="permission-group__header">
            <span class="permission-group__icon">✏️</span>
            <h3 class="permission-group__title">编辑操作权限 (14 个)</h3>
          </div>
          <p class="permission-group__desc">控制节点、连线的增删改操作。</p>

          <ul class="compact-permission-list">
            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>从左侧面板拖拽节点到画布</div>
                    <div><strong>相关权限：</strong>通常与 showNodePalette 配合</div>
                  </div>
                </template>
                <code class="permission-key">canAddNode</code>
              </a-tooltip>
              <span class="permission-desc">允许从节点面板拖拽添加新节点</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canDrag</code>
              <span class="permission-desc">允许拖动节点改变位置</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canConnect</code>
              <span class="permission-desc">允许创建节点之间的连线</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canDelete</code>
              <span class="permission-desc">允许删除节点和连线 (Delete 键)</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canCopy</code>
              <span class="permission-desc">允许复制节点 (Ctrl+C)</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>依赖关系：</strong>通常与 canCopy 配合使用</div>
                  </div>
                </template>
                <code class="permission-key">canPaste</code>
              </a-tooltip>
              <span class="permission-desc">允许粘贴节点 (Ctrl+V)</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canGroup</code>
              <span class="permission-desc">允许将多个节点组合成组</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canToFront</code>
              <span class="permission-desc">允许将元素移到最前层</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canToBack</code>
              <span class="permission-desc">允许将元素移到最后层</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>节点调整大小的控制点显示/隐藏</div>
                    <div><strong>功能说明：</strong>控制 X6 Transform 插件的 resizing 功能</div>
                    <div><strong>依赖关系：</strong>需要与画布配置 interaction.resizable 同时为 true</div>
                    <div><strong>默认值：</strong>false（所有模式默认禁用）</div>
                  </div>
                </template>
                <code class="permission-key">canTransform</code>
              </a-tooltip>
              <span class="permission-desc">允许调整节点大小（拖拽控制点）</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>依赖关系：</strong>为 false 时，所有具体对齐功能都不可用</div>
                  </div>
                </template>
                <code class="permission-key">canAlign</code>
              </a-tooltip>
              <span class="permission-desc">对齐功能总开关</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canAlignLeft</code>
              <span class="permission-desc">允许节点左对齐</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canAlignRight</code>
              <span class="permission-desc">允许节点右对齐</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canAlignTop</code>
              <span class="permission-desc">允许节点上对齐</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canAlignBottom</code>
              <span class="permission-desc">允许节点下对齐</span>
            </li>
          </ul>
        </div>

        <!-- 选择操作权限 -->
        <div class="permission-group">
          <div class="permission-group__header">
            <span class="permission-group__icon">🎯</span>
            <h3 class="permission-group__title">选择操作权限 (4 个)</h3>
          </div>

          <ul class="compact-permission-list">
            <li class="compact-permission-item">
              <code class="permission-key">canSelectNode</code>
              <span class="permission-desc">允许选中节点</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canSelectEdge</code>
              <span class="permission-desc">允许选中连线</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>影响范围：</strong>blank:click 事件处理逻辑</div>
                    <div><strong>行为说明：</strong>为 true 时点击画布会清空选择并还原所有元素状态；为 false 时保持当前状态</div>
                    <div><strong>适用场景：</strong>需要手动控制状态清理的业务逻辑</div>
                  </div>
                </template>
                <code class="permission-key">canSelectCanvas</code>
              </a-tooltip>
              <span class="permission-desc">点击画布时清空选择并还原状态</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canMultipleSelect</code>
              <span class="permission-desc">允许同时选中多个节点（Ctrl + 点击 / 框选）</span>
            </li>

            <li class="compact-permission-item">
              <a-tooltip placement="right">
                <template #title>
                  <div class="tooltip-content">
                    <div><strong>依赖关系：</strong>需要 canMultipleSelect 同时为 true</div>
                  </div>
                </template>
                <code class="permission-key">canSelectAll</code>
              </a-tooltip>
              <span class="permission-desc">允许全选所有节点 (Ctrl+A)</span>
            </li>
          </ul>
        </div>

        <!-- 历史操作 + 视图操作 + 导入导出 -->
        <div class="permission-group">
          <div class="permission-group__header">
            <span class="permission-group__icon">⏱️</span>
            <h3 class="permission-group__title">其他权限 (10 个)</h3>
          </div>

          <ul class="compact-permission-list">
            <li class="compact-permission-item">
              <code class="permission-key">canUndo</code>
              <span class="permission-desc">允许撤销操作 (Ctrl+Z)</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canRedo</code>
              <span class="permission-desc">允许重做操作 (Ctrl+Y)</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canZoom</code>
              <span class="permission-desc">允许缩放画布</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canPan</code>
              <span class="permission-desc">允许拖拽画布</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canFitView</code>
              <span class="permission-desc">允许适应窗口</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canResetView</code>
              <span class="permission-desc">允许重置视图</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canHoverNode</code>
              <span class="permission-desc">鼠标悬停时高亮节点</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canHoverEdge</code>
              <span class="permission-desc">鼠标悬停时高亮连线</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canImport</code>
              <span class="permission-desc">允许导入流程数据</span>
            </li>

            <li class="compact-permission-item">
              <code class="permission-key">canExport</code>
              <span class="permission-desc">允许导出流程数据</span>
            </li>
          </ul>
        </div>
      </div>
    </section>

    <!-- 5.3 内置模式 -->
    <section id="builtin-modes" class="ch-section">
      <h2 class="ch-section__title">5.2 内置模式</h2>
      <p class="ch-text">系统提供三种内置模式，每种模式的所有权限默认都为 <code>true</code>。</p>

      <!-- Design 模式 -->
      <div class="mode-card">
        <div class="mode-card__header">
          <span class="mode-card__icon">✏️</span>
          <h3 class="mode-card__title">Design 模式</h3>
          <span class="mode-card__badge mode-card__badge--design">设计模式</span>
        </div>
        <p class="mode-card__desc">
          完整的流程设计功能，适用于流程设计、编辑、配置等场景。所有功能默认开启。
        </p>
        <div class="ch-code-block">
          <CodePreviewer demo-name="demo-permission-design" />
        </div>
      </div>

      <!-- Readonly 模式 -->
      <div class="mode-card">
        <div class="mode-card__header">
          <span class="mode-card__icon">👁️</span>
          <h3 class="mode-card__title">Readonly 模式</h3>
          <span class="mode-card__badge mode-card__badge--readonly">只读模式</span>
        </div>
        <p class="mode-card__desc">
          只读查看模式，适用于流程查看、审批、存档等场景。所有权限默认为 true，需要根据实际需求覆盖。
        </p>
        <div class="ch-code-block">
          <pre><code><span class="code-comment">// 典型的只读配置：禁用所有编辑功能</span>
<span class="code-tag">&lt;FlowDesigner</span>
  <span class="code-attr">mode</span>=<span class="code-string">"readonly"</span>
  <span class="code-attr">:permissionConfig</span>=<span class="code-string">"</span>{
    readonly: {
      showToolbar: <span class="code-boolean">false</span>,
      showNodePalette: <span class="code-boolean">false</span>,
      canAddNode: <span class="code-boolean">false</span>,
      canDrag: <span class="code-boolean">false</span>,
      canConnect: <span class="code-boolean">false</span>,
      canDelete: <span class="code-boolean">false</span>,
      canSelectEdge: <span class="code-boolean">false</span>
    }
  }<span class="code-string">"</span>
<span class="code-tag">/&gt;</span></code></pre>
        </div>
        <CodePreviewer demo-name="demo-permission-readonly" />
      </div>

      <!-- Preview 模式 -->
      <div class="mode-card">
        <div class="mode-card__header">
          <span class="mode-card__icon">📺</span>
          <h3 class="mode-card__title">Preview 模式</h3>
          <span class="mode-card__badge mode-card__badge--preview">预览模式</span>
        </div>
        <p class="mode-card__desc">
          预览展示模式，适用于演示、汇报、大屏展示等场景。design,readonly,preview所有权限默认为 true，不需要的权限需要手动置为false
        </p>
        <div class="ch-code-block">
          <pre><code><span class="code-comment">// 典型的预览配置：精简 UI，保留基本交互</span>
<span class="code-tag">&lt;FlowDesigner</span>
  <span class="code-attr">mode</span>=<span class="code-string">"preview"</span>
  <span class="code-attr">:permissionConfig</span>=<span class="code-string">"</span>{
    preview: {
      showToolbar: <span class="code-boolean">false</span>,
      showNodePalette: <span class="code-boolean">false</span>,
      showPropertiesPanel: <span class="code-boolean">false</span>,
      showContextMenu: <span class="code-boolean">false</span>,
      showMinimap: <span class="code-boolean">false</span>,

      canDrag: <span class="code-boolean">false</span>
      canConnect: <span class="code-boolean">false</span>
      canDelete: <span class="code-boolean">false</span>
      canCopy: <span class="code-boolean">false</span>
      canPaste: <span class="code-boolean">false</span>
      canGroup: <span class="code-boolean">false</span>
      canToFront: <span class="code-boolean">false</span>
      canToBack: <span class="code-boolean">false</span>
      canAddNode: <span class="code-boolean">false</span>

      canMultipleSelect: <span class="code-boolean">false</span>
      canSelectAll: <span class="code-boolean">false</span>

      canAlign: <span class="code-boolean">false</span>

      canImport: <span class="code-boolean">false</span>
      canExport: <span class="code-boolean">false</span>
      canRedo: <span class="code-boolean">false</span>
      canUndo: <span class="code-boolean">false</span>

      canHoverNode: <span class="code-boolean">false</span>
      canHoverEdge: <span class="code-boolean">false</span>
      canSelectNode: <span class="code-boolean">false</span>
      canSelectEdge: <span class="code-boolean">false</span>
      canNodeTooltip: <span class="code-boolean">false</span>
      canEdgeTooltip: <span class="code-boolean">false</span>
    }
  }<span class="code-string">"</span>
<span class="code-tag">/&gt;</span></code></pre>
        </div>
        <div style="min-height: 380px;">
          <CodePreviewer demo-name="demo-permission-preview" />
        </div>

      </div>

      <!-- 模式对比 -->
      <div class="comparison-card">
        <h3 class="comparison-card__title">📊 模式对比</h3>
        <div class="ch-callout ch-callout--warning">
          <strong>重要提示：</strong>
          三种内置模式的所有权限默认都是 <code>true</code>。这意味着：
          <ul>
            <li>如果直接使用 <code>mode="readonly"</code> 而不配置权限，效果与 design 模式完全相同</li>
            <li>必须通过 <code>permissionConfig</code> 显式配置需要限制的权限</li>
            <li>这种设计让你可以灵活地只覆盖需要修改的权限，其他保持开放</li>
          </ul>
        </div>

        <table class="comparison-table">
          <thead>
            <tr>
              <th>场景</th>
              <th>推荐模式</th>
              <th>典型权限配置</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td>流程设计</td>
              <td><span class="mode-badge mode-badge--design">Design</span></td>
