    <!-- 5.6 实战示例 -->
    <section id="examples" class="ch-section">
      <h2 class="ch-section__title">5.6 实战示例</h2>

      <!-- 示例1: 只读查看器 -->
      <div class="example-card">
        <div class="example-card__header">
          <span class="example-card__badge">示例 1</span>
          <h3 class="example-card__title">只读流程查看器</h3>
        </div>
        <p class="example-card__desc">
          <strong>场景：</strong>流程审批、存档查看、历史记录展示<br>
          <strong>需求：</strong>只允许查看和导出，禁止任何编辑操作
        </p>

        <div class="ch-code-block">
          <pre><code><span class="code-tag">&lt;FlowDesigner</span>
  <span class="code-attr">mode</span>=<span class="code-string">"readonly"</span>
  <span class="code-attr">:permissionConfig</span>=<span class="code-string">"</span>{
    readonly: {
      showToolbar: <span class="code-boolean">false</span>,
      showNodePalette: <span class="code-boolean">false</span>,
      canAddNode: <span class="code-boolean">false</span>,
      canDrag: <span class="code-boolean">false</span>,
      canConnect: <span class="code-boolean">false</span>,
      canDelete: <span class="code-boolean">false</span>,
      canSelectNode: <span class="code-boolean">false</span>,
      canSelectEdge: <span class="code-boolean">false</span>,
      canZoom: <span class="code-boolean">true</span>,
      canPan: <span class="code-boolean">true</span>,
      canExport: <span class="code-boolean">true</span>
    }
  }<span class="code-string">"</span>
<span class="code-tag">/&gt;</span></code></pre>
        </div>

        <div class="ch-callout ch-callout--info">
          <strong>关键配置：</strong>
          <ul>
            <li>隐藏工具栏和节点面板，减少干扰</li>
            <li>禁用所有编辑和选择操作</li>
            <li>保留缩放和平移，方便查看大型流程</li>
            <li>保留导出功能，允许下载查看</li>
          </ul>
        </div>
      </div>

      <!-- 示例2: 根据角色配置权限 -->
      <div class="example-card">
        <div class="example-card__header">
          <span class="example-card__badge">示例 2</span>
          <h3 class="example-card__title">根据用户角色动态配置权限</h3>
        </div>
        <p class="example-card__desc">
          <strong>场景：</strong>多角色协作平台<br>
          <strong>需求：</strong>管理员全部权限，编辑者部分权限，查看者只读
        </p>

        <div class="ch-code-block">
          <pre><code><span class="code-tag">&lt;script</span> <span class="code-attr">setup</span><span class="code-tag">&gt;</span>
<span class="code-keyword">const</span> userRole = ref(<span class="code-string">'viewer'</span>)

<span class="code-keyword">const</span> getPermissionsByRole = (mode) => {
  <span class="code-keyword">const</span> base = {
    canSelectNode: <span class="code-boolean">true</span>,
    canZoom: <span class="code-boolean">true</span>,
    canPan: <span class="code-boolean">true</span>
  }

  <span class="code-keyword">if</span> (userRole.value === <span class="code-string">'admin'</span>) {
    <span class="code-keyword">return</span> { ...base, canAddNode: <span class="code-boolean">true</span>, canDrag: <span class="code-boolean">true</span>, canDelete: <span class="code-boolean">true</span> }
  }

  <span class="code-keyword">if</span> (userRole.value === <span class="code-string">'editor'</span>) {
    <span class="code-keyword">return</span> { ...base, canAddNode: <span class="code-boolean">true</span>, canDrag: <span class="code-boolean">true</span>, canDelete: <span class="code-boolean">false</span> }
  }

  <span class="code-keyword">return</span> { ...base, canAddNode: <span class="code-boolean">false</span>, canDrag: <span class="code-boolean">false</span> }
}
<span class="code-tag">&lt;/script&gt;</span>

<span class="code-tag">&lt;template&gt;</span>
  <span class="code-tag">&lt;FlowDesigner</span>
    <span class="code-attr">mode</span>=<span class="code-string">"design"</span>
    <span class="code-attr">:getPermissions</span>=<span class="code-string">"getPermissionsByRole"</span>
  <span class="code-tag">/&gt;</span>
<span class="code-tag">&lt;/template&gt;</span></code></pre>
        </div>

        <div class="ch-callout ch-callout--info">
          <strong>设计要点：</strong>
          <ul>
            <li>使用 <code>getPermissions</code> 函数动态计算权限</li>
            <li>定义基础权限集合，避免重复代码</li>
            <li>根据角色递增权限，清晰易维护</li>
          </ul>
        </div>
      </div>

      <!-- 示例3: 动态权限切换 -->
      <div class="example-card">
        <div class="example-card__header">
          <span class="example-card__badge">示例 3</span>
          <h3 class="example-card__title">运行时动态切换权限</h3>
        </div>
        <p class="example-card__desc">
          <strong>场景：</strong>流程审批系统<br>
          <strong>需求：</strong>根据审批状态动态调整可用功能
        </p>

        <div class="ch-code-block">
          <pre><code><span class="code-tag">&lt;script</span> <span class="code-attr">setup</span><span class="code-tag">&gt;</span>
<span class="code-keyword">const</span> flowStatus = ref(<span class="code-string">'editing'</span>) <span class="code-comment">// editing / reviewing / approved</span>

<span class="code-keyword">const</span> permissionConfig = computed(() => ({
  design: flowStatus.value === <span class="code-string">'editing'</span> ? {
    <span class="code-comment">// 编辑中：全部开放</span>
  } : flowStatus.value === <span class="code-string">'reviewing'</span> ? {
    <span class="code-comment">// 审批中：禁止编辑</span>
    canAddNode: <span class="code-boolean">false</span>,
    canDrag: <span class="code-boolean">false</span>,
    canDelete: <span class="code-boolean">false</span>
  } : {
    <span class="code-comment">// 已通过：完全锁定</span>
    showToolbar: <span class="code-boolean">false</span>,
    canAddNode: <span class="code-boolean">false</span>,
    canDrag: <span class="code-boolean">false</span>,
    canSelectNode: <span class="code-boolean">false</span>
  }
}))
<span class="code-tag">&lt;/script&gt;</span>

<span class="code-tag">&lt;template&gt;</span>
  <span class="code-tag">&lt;FlowDesigner</span>
    <span class="code-attr">mode</span>=<span class="code-string">"design"</span>
    <span class="code-attr">:permissionConfig</span>=<span class="code-string">"permissionConfig"</span>
  <span class="code-tag">/&gt;</span>
<span class="code-tag">&lt;/template&gt;</span></code></pre>
        </div>
      </div>

      <!-- 示例4: 多模式，& 自定义扩展模式 & 自定义扩展权限粒度 -->
      <div class="example-card">
        <div class="example-card__header">
          <span class="example-card__badge">示例 4</span>
          <h3 class="example-card__title">多模式，& 自定义扩展模式 & 自定义扩展权限粒度</h3>
        </div>

